find和findIndex分别用于找出第一个符合条件的成员及位置；filter用于过滤或筛选数组，可实现判断值是否存在、去重等；map用于数组映射；some判断是否有元素满足条件；every检测所有元素是否都满足条件；reduce用于累加数组值


1、find、findIndex数组实例的find方法，用于找出第一个符合条件的数组成员。它的参数是一个回调函数，所有数组成员依次执行该回调函数，直到找出第一个返回值为true的成员，然后返回该成员。如果没有符合条件的成员，则返回undefined。
var array = [&#39;60&#39;,&#39;33&#39;,&#39;77&#39;,&#39;20&#39;,&#39;42&#39;]
var newArray = array.find(item =&gt; item&lt;40) 
console.log(newArray); //33find方法的回调函数可以接受三个参数，依次为当前的值、当前的位置和原数组。
[1, 5, 10, 15].find(function(value, index, arr) {
  return value &gt; 9;
}) // 10数组实例的findIndex方法的用法与find方法类似，不同的是：findindex返回的是第一个符合条件的数组成员的位置，如果所有成员都不符合条件，则返回-1。
[1, 5, 10, 15].findIndex(function(value, index, arr) {
  return value &gt; 9;
}) // 2 (2是索引)这两个方法都可以接受第二个参数，用来绑定回调函数的this对象。find函数接收了第二个参数person对象，回调函数中的this对象指向person对象。
function f(v){
  return v &gt; this.age;
}
let person = {name: &#39;John&#39;, age: 20};
[10, 12, 26, 15].find(f, person);    // 26另外，这两个方法都可以发现NaN，弥补了数组的indexOf方法的不足。indexOf方法无法识别数组的NaN成员，但是findIndex方法可以借助Object.is方法做到。
[NaN].indexOf(NaN)                            // -1
[NaN].findIndex(y =&gt; Object.is(NaN, y))        // 02、filter数组的过滤或筛选功能，根据筛选条件返回一个包含符合条件元素的新数组，不影响原数组，筛选条件写在一个函数中
const array=[
    {id:1,name:&#39;javascript&#39;,date:&#39;2021-06-01&#39;},
    {id:2,name:&#39;css&#39;,date:&#39;2021-06-01&#39;},
    {id:3,name:&#39;vuejs&#39;,date:&#39;2021-06-01&#39;}
]
const newArray=array.filter(item=&gt;item.id==3);    //判断是否存在某个值
console.log(newArray);         // [{id:3,name:&quot;vuejs&quot;,date:&quot;2021-06-01&quot;}]

const newArray=array.filter(item=&gt;item.id!=3);    //过滤掉id!=3的项
console.log(newArray);        // [{id:3,name:&quot;vuejs&quot;,date:&quot;2021-06-01&quot;},{id:3,name:&quot;vuejs&quot;,date:&quot;2021-06-01&quot;}]


const array=[&#39;A&#39;,&#39;B&#39;,&#39;&#39;,&#39;D&#39;,&#39;&#39;,&#39;F&#39;,undefined, null]
const newArray=array.filter(item=&gt;item);    去掉空数组空字符串、undefined、null
console.log(newArray); //[&quot;A&quot;,&quot;B&quot;,&quot;D&quot;,&quot;F&quot;]

var array = [20,80,50,96,40]
var newArray = array.filter(item =&gt; item&gt;40)      //过滤不符合条件的项
console.log(newArray); //[80,50,96]

var arr = [1, 2, 2, 3, 4, 5, 5, 6, 7, 7,8,8,0,8,6,3,4,56,2];
var arr2 = arr.filter((x, index,self)=&gt;self.indexOf(x)===index)      //数组去重
console.log(arr2); //[1, 2, 3, 4, 5, 6, 7, 8, 0, 56]3、mapmap方法：可以简单的理解为映射
var arr=[1,2,3,4]; 
console.log( arr.map((n)=&gt;n*n) );//[1, 4, 9,16] 
console.log( arr.map((n)=&gt;n-1) );//[0, 1, 2, 3]数组的映射，返回一个新数组，其值是通过函数处理过的值
let arr = [2,3,5,6]
let arr1 = arr.map(function(item){
   return item +1;
})
console.log(arr1)//[3,4,6,7]  let arr = [2,3,5,6,7,8]

let arr1 = arr.map(function(item){
   return item &gt;5;
})
console.log(arr1)//[false,false,false,true,true,true]4、somesome() 方法会依次执行数组的每个元素：如果有一个元素满足条件，则表达式返回true , 剩余的元素不会再执行检测。 　　如果没有满足条件的元素，则返回false
let arr = [2, 4, 6, 8]; 
let flag = arr.some(function(item) {
    return item &gt; 5 
}); 
console.log(flag); //true 5、everyevery（）检测数组中的所有元素是否都满足函数的中的筛选条件都满足返回true，否则返回false
let arr = [2, 4, 6, 8];
let flag = arr.every(function(item) {
    return item &gt; 6 
}); 
console.log(flag); //false6、reduce从左到右累加数组中的值，最后得到的仍是一个值
let arr = [2,3,5,6,7,8,&#39;a&#39;] 
let arr1 =  arr.reduce(function(val,item,index,origin){
     //val是累加值，item是当前值，index下标从1开始，arr[0]默认为第一次的累加值，origin是数组本身
    console.log(val,item,index,origin)
    return val+item 
}) 
console.log(arr1)//  2+3+5+6+7+8 = 31, 31+a = &#39;31a&#39;

在IE中使用CSS3的旋转效果是不能实现的，，但是我又想把IE旋转效果跟其他浏览使用CSS3 rotate(deg)一样。在百度找了一下，发现IE里面有一款滤镜，可以实现旋转角度。
代码如下：  
filter: progid:DXImageTransform.Microsoft.Matrix(sizingMethod=&#39;auto expand&#39;, M11=0.70710678, M12=-0.70710678, M21=0.70710678, M22=0.70710678);  
假如红色的矩形是我们需要旋转的元素，蓝色矩形是旋转之后的位置，也就是说(0,1)和(1,0)这两个坐标旋转a角之后变成了(x,y)和(m,-n)，我们只要知道他们的变换关系就好。那么(x,y)和(m,-n)可以用简单的三角函数算出得到(sin(a),cos(a))和(cos(a),-sin(a))。把这个结果代入单位矩阵中得到
{    m    -n    }  
 x    y  
也就是  
{    cos(a)    -sin(a)    }  
 sin(a)    cos(a)  
假如a是45°就可以得到如下值。  
{    0.707    -0.707    }  
 0.707    0.707  

sin()  cos()  可在自己电脑上打开计算器进行计算。如下图计算了一个45度后的sin值。  其实旋转完了还是有些问题的存在。问题就是元素旋转了IE和FF的中心点不一样了。IE偏离了中心点，为了解决这个问题还是要计算一下。我们先要计算出它旋转后的大小，然后就能知道它旋转后大小的增量，偏移量就是这个增量的一半。公式：  
W=|sin(a)\*h|+|cos(a)\*w|，H=|sin(a)\*w|+|cos(a)\*h|  我这个元素的宽高都是200px…那么旋转后282这样。增量就是82.。。偏移量就是增量的一半那就是41.。。所以加这个属性margin:-41px;….不这个属性只是针对IE。。所以Ie8：  
margin:-41px\\0;        ie7  : *margin:-41px;        ie6:margin:-41px;  有些在IE中不能实现CSS3样式效果，可以使用IE的滤镜来实现IE滤镜Alpha：设置透明层次.   
